313	```go
314	package runner
315	
316	import (
317	    "encoding/json"
318	    "fmt"
319	    "net/http"
320	    "strings"
321	    "time"
322	)
323	
324	type assetlinkStatement struct {
325	    Relation []string `json:"relation"`
326	    Target   struct {
327	        Namespace   string `json:"namespace"`
328	        PackageName string `json:"package_name"`
329	    } `json:"target"`
330	}
331	
332	func CheckAssetlinks(baseURL, expectedPackage string) AssertionResult {
333	    url := strings.TrimRight(baseURL, "/") + "/.well-known/assetlinks.json"
334	    client := &http.Client{Timeout: 10 * time.Second}
335	    resp, err := client.Get(url)
336	    if err != nil {
337	        return AssertionResult{Type: "deep_link.assetlinks", Passed: false, Expected: "assetlinks.json accessible", Actual: fmt.Sprintf("HTTP error: %v", err)}
338	    }
339	    defer resp.Body.Close()
340	    if resp.StatusCode != 200 {
341	        return AssertionResult{Type: "deep_link.assetlinks", Passed: false, Expected: "HTTP 200", Actual: fmt.Sprintf("HTTP %d", resp.StatusCode)}
342	    }
343	    var statements []assetlinkStatement
344	    if err := json.NewDecoder(resp.Body).Decode(&statements); err != nil {
345	        return AssertionResult{Type: "deep_link.assetlinks", Passed: false, Expected: "valid JSON", Actual: fmt.Sprintf("parse error: %v", err)}
346	    }
347	    for _, s := range statements {
348	        hasRelation := false
349	        for _, r := range s.Relation {
350	            if r == "delegate_permission/common.handle_all_urls" { hasRelation = true; break }
351	        }
352	        if hasRelation && s.Target.Namespace == "android_app" {
353	            if expectedPackage == "" || s.Target.PackageName == expectedPackage {
354	                return AssertionResult{Type: "deep_link.assetlinks", Passed: true}
355	            }
356	        }
357	    }
358	    return AssertionResult{Type: "deep_link.assetlinks", Passed: false, Expected: fmt.Sprintf("package %q in assetlinks.json", expectedPackage), Actual: "no matching statement found"}
359	}
360	
361	func CheckAASA(baseURL, expectedBundleID string) AssertionResult {
362	    // Try both standard paths
363	    for _, path := range []string{"/apple-app-site-association", "/.well-known/apple-app-site-association"} {
364	        url := strings.TrimRight(baseURL, "/") + path
365	        client := &http.Client{Timeout: 10 * time.Second}
366	        resp, err := client.Get(url)
367	        if err != nil || resp.StatusCode != 200 {
368	            resp.Body.Close()
369	            continue
370	        }
371	        var aasa struct {
372	            Applinks struct {
373	                Details []struct {
374	                    AppIDs []string `json:"appIDs"`
375	                } `json:"details"`
376	            } `json:"applinks"`
377	        }
378	        err = json.NewDecoder(resp.Body).Decode(&aasa)
379	        resp.Body.Close()
380	        if err != nil { continue }
381	        for _, d := range aasa.Applinks.Details {
382	            for _, id := range d.AppIDs {
383	                if expectedBundleID == "" || strings.HasSuffix(id, expectedBundleID) {
384	                    return AssertionResult{Type: "deep_link.aasa", Passed: true}
385	                }
386	            }
387	        }
388	    }
389	    return AssertionResult{Type: "deep_link.aasa", Passed: false, Expected: "valid AASA with matching bundle ID", Actual: "no matching apple-app-site-association found"}
390	}
