	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(404)
	}))
	defer srv.Close()

	result := CheckAssetlinks(srv.URL, "com.myapp")
	if result.Passed {
		t.Error("expected failure for HTTP 404")
	}
}

