1	package runner
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"net/http"
7		"strings"
8		"time"
9	)
10	
11	type assetlinkStatement struct {
12		Relation []string `json:"relation"`
13		Target   struct {
14			Namespace   string `json:"namespace"`
15			PackageName string `json:"package_name"`
16		} `json:"target"`
17	}
18	
19	// CheckAssetlinks fetches and validates .well-known/assetlinks.json for Android App Links.
20	func CheckAssetlinks(baseURL, expectedPackage string) AssertionResult {
21		url := strings.TrimRight(baseURL, "/") + "/.well-known/assetlinks.json"
22		client := &http.Client{Timeout: 10 * time.Second}
23		resp, err := client.Get(url)
24		if err != nil {
25			return AssertionResult{Type: "deep_link.assetlinks", Passed: false, Expected: "assetlinks.json accessible", Actual: fmt.Sprintf("HTTP error: %v", err)}
26		}
27		defer resp.Body.Close()
28		if resp.StatusCode != 200 {
29			return AssertionResult{Type: "deep_link.assetlinks", Passed: false, Expected: "HTTP 200", Actual: fmt.Sprintf("HTTP %d", resp.StatusCode)}
30		}
31		var statements []assetlinkStatement
32		if err := json.NewDecoder(resp.Body).Decode(&statements); err != nil {
33			return AssertionResult{Type: "deep_link.assetlinks", Passed: false, Expected: "valid JSON", Actual: fmt.Sprintf("parse error: %v", err)}
34		}
35		for _, s := range statements {
36			hasRelation := false
37			for _, r := range s.Relation {
38				if r == "delegate_permission/common.handle_all_urls" {
39					hasRelation = true
40					break
41				}
42			}
43			if hasRelation && s.Target.Namespace == "android_app" {
44				if expectedPackage == "" || s.Target.PackageName == expectedPackage {
45					return AssertionResult{Type: "deep_link.assetlinks", Passed: true}
46				}
47			}
48		}
49		return AssertionResult{
